raw_emission:
{
  "thought_process": "The workflow requires branching for evolved lines after ancestor processing to ensure concrete, separate handling of subtraction and normalization before shared export.",
  "workflow": [
    {
      "step_id": 1,
      "tool_name": "spades_assemble",
      "objective": "Assemble the ancestor reads into the working bacterial reference, preferring the scaffolded assembly output when SPAdes produces it",
      "depends_on": [],
      "branch_id": "ancestor_ref",
      "parameter_hints": {
        "careful": true,
        "deliverable": "ancestor_scaffolds.fasta"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 2,
      "tool_name": "prodigal_annotate",
      "objective": "Annotate the assembled ancestor scaffold reference to produce a GFF for downstream variant effect annotation",
      "depends_on": [
        1
      ],
      "branch_id": "ancestor_ref",
      "parameter_hints": {
        "deliverable": "ancestor_annotated.gff"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 3,
      "tool_name": "bwa_mem_align",
      "objective": "Align ancestor reads to the assembled scaffold reference",
      "depends_on": [
        1
      ],
      "branch_id": "ancestor_align",
      "parameter_hints": {
        "deliverable": "ancestor_aligned.bam",
        "sample_name": "ancestor"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 4,
      "tool_name": "freebayes_call",
      "objective": "Call haploid ancestor variants to define background / assembly-supporting sites",
      "depends_on": [
        3
      ],
      "branch_id": "ancestor_call",
      "parameter_hints": {
        "ploidy": 1,
        "deliverable": "ancestor_variants.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 5,
      "tool_name": "bwa_mem_align",
      "objective": "Align evolved line 1 reads to the assembled scaffold reference",
      "depends_on": [
        1
      ],
      "branch_id": "evol1_align",
      "parameter_hints": {
        "deliverable": "evol1_aligned.bam",
        "sample_name": "evol1"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 6,
      "tool_name": "bwa_mem_align",
      "objective": "Align evolved line 2 reads to the assembled scaffold reference",
      "depends_on": [
        1
      ],
      "branch_id": "evol2_align",
      "parameter_hints": {
        "deliverable": "evol2_aligned.bam",
        "sample_name": "evol2"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 7,
      "tool_name": "freebayes_call",
      "objective": "Call haploid evolved-line 1 variants",
      "depends_on": [
        5
      ],
      "branch_id": "evol1_call",
      "parameter_hints": {
        "ploidy": 1,
        "deliverable": "evol1_variants.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 8,
      "tool_name": "freebayes_call",
      "objective": "Call haploid evolved-line 2 variants",
      "depends_on": [
        6
      ],
      "branch_id": "evol2_call",
      "parameter_hints": {
        "ploidy": 1,
        "deliverable": "evol2_variants.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 9,
      "tool_name": "bcftools_filter_run",
      "objective": "Filter ancestor callset to high-quality sites for background definition",
      "depends_on": [
        4
      ],
      "branch_id": "ancestor_filter",
      "parameter_hints": {
        "deliverable": "ancestor_filtered.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 10,
      "tool_name": "bcftools_filter_run",
      "objective": "Filter evolved line 1 callset to high-quality sites",
      "depends_on": [
        7
      ],
      "branch_id": "evol1_filter",
      "parameter_hints": {
        "deliverable": "evol1_filtered.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 11,
      "tool_name": "bcftools_filter_run",
      "objective": "Filter evolved line 2 callset to high-quality sites",
      "depends_on": [
        8
      ],
      "branch_id": "evol2_filter",
      "parameter_hints": {
        "deliverable": "evol2_filtered.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 12,
      "tool_name": "bcftools_norm_run",
      "objective": "Normalize evolved line 1 variants relative to ancestor reference",
      "depends_on": [
        10
      ],
      "branch_id": "evol1_norm",
      "parameter_hints": {
        "multiallelic_mode": "-any",
        "deliverable": "evol1_normalized.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 13,
      "tool_name": "bcftools_norm_run",
      "objective": "Normalize evolved line 2 variants relative to ancestor reference",
      "depends_on": [
        11
      ],
      "branch_id": "evol2_norm",
      "parameter_hints": {
        "multiallelic_mode": "-any",
        "deliverable": "evol2_normalized.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 14,
      "tool_name": "bcftools_isec_run",
      "objective": "Subtract ancestor-supported sites from evolved line 1 callset",
      "depends_on": [
        12,
        9
      ],
      "branch_id": "evol1_subtract",
      "parameter_hints": {
        "mode": "complement",
        "deliverable": "evol1_minus_ancestor.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 15,
      "tool_name": "bcftools_isec_run",
      "objective": "Subtract ancestor-supported sites from evolved line 2 callset",
      "depends_on": [
        13,
        9
      ],
      "branch_id": "evol2_subtract",
      "parameter_hints": {
        "mode": "complement",
        "deliverable": "evol2_minus_ancestor.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 16,
      "tool_name": "snpeff_annotate",
      "objective": "Annotate evolved line 1 subtracted variants with functional impact",
      "depends_on": [
        14,
        2
      ],
      "branch_id": "evol1_annotate",
      "parameter_hints": {
        "deliverable": "evol1_annotated.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 17,
      "tool_name": "snpeff_annotate",
      "objective": "Annotate evolved line 2 subtracted variants with functional impact",
      "depends_on": [
        15,
        2
      ],
      "branch_id": "evol2_annotate",
      "parameter_hints": {
        "deliverable": "evol2_annotated.vcf"
      },
      "downstream_constraints": []
    },
    {
      "step_id": 18,
      "tool_name": "shared_variants_export_run",
      "objective": "Write the final shared-variant CSV from the normalized annotated evolved callsets with the exact required columns",
      "depends_on": [
        16,
        17
      ],
      "branch_id": "final_export",
      "parameter_hints": {
        "header_case": "upper",
        "min_impact": "MODERATE",
        "deliverable": "shared_variants.csv"
      },
      "downstream_constraints": []
    }
  ],
  "global_constraints": [
    "Use assembled ancestor scaffolds as the reference for all alignment and variant calling steps.",
    "Ensure prodigal annotation is complete before snpeff_annotate runs."
  ],
  "final_deliverables": [
    "shared_variants.csv"
  ]
}
